insert into portfolio_cases (client_name, slug, industry, logo_image_url, short_description, problem, goal, solution, services_provided, platforms_used, strategy, execution, results_summary, metrics_json, cover_label, cover_image_url, gallery_images, testimonial, published) values ('O 2 Y Hair Fixing', 'o-2-y-hair-fixing', 'Hair Fixing / Hair Replacement / Men''s Grooming Service', '/assets/client-logos/o2y.png', 'A trust-based digital funnel for hair fixing enquiries, transformation content, Meta Ads, and WhatsApp consultations.', 'The brand had a strong service offering, but hair fixing is a high-trust service. Customers had fears about natural look, privacy, safety, duration, cost, and whether others would notice.', 'Build trust through real transformation content, educate men facing hair loss, and generate quality call and WhatsApp enquiries.', 'We managed the brand''s social media, created transformation-led content, shot and edited videos, and ran Meta Ads focused on enquiry generation.', array['Social Media Management', 'Meta Ads', 'Lead Generation', 'Video Shooting', 'Video Editing', 'Content Creation']::text[], array['Instagram', 'Facebook', 'Meta Ads Manager', 'WhatsApp']::text[], array['Used a trust-based funnel: show the problem, show transformation, build confidence, push to WhatsApp, and convert into consultation.', 'Created content around natural look, privacy, cost clarity, safety, duration, and confidence after hair fixing.', 'Planned Meta campaigns for hair loss pain points, transformation proof, local targeting, and retargeting interested users.', 'Moved interested viewers from reels and ads into call or WhatsApp enquiry conversations.']::text[], array['Created Instagram and Facebook content plans with reels, captions, hashtags, stories, and enquiry-focused CTA posts.', 'Shot before-after transformation videos, consultation clips, process visuals, studio shots, and close-up hair patch content.', 'Edited transformation reels with hook-based overlays, fast cuts, premium grooming visuals, CTA endings, and WhatsApp callouts.', 'Built lead generation campaigns for serious enquiries instead of only views or likes.']::text[], 'A stronger trust-building content system and enquiry-focused funnel for men actively looking for hair fixing solutions.', '{"summary":"Trust Content: Built, WhatsApp Funnel: Active, Lead Quality: Focused"}'::jsonb, 'Hair Fixing Lead Funnel', '', array[]::text[], 'Hair loss is not the end of confidence. The right hair fixing solution can bring back your natural look.', true) on conflict (slug) do update set client_name = excluded.client_name, industry = excluded.industry, logo_image_url = excluded.logo_image_url, short_description = excluded.short_description, problem = excluded.problem, goal = excluded.goal, solution = excluded.solution, services_provided = excluded.services_provided, platforms_used = excluded.platforms_used, strategy = excluded.strategy, execution = excluded.execution, results_summary = excluded.results_summary, metrics_json = excluded.metrics_json, cover_label = excluded.cover_label, testimonial = excluded.testimonial, published = excluded.published, updated_at = now();
insert into portfolio_cases (client_name, slug, industry, logo_image_url, short_description, problem, goal, solution, services_provided, platforms_used, strategy, execution, results_summary, metrics_json, cover_label, cover_image_url, gallery_images, testimonial, published) values ('Grace Speech and Hearing', 'grace-speech-and-hearing', 'Speech & Hearing Clinic / Hearing Aid Centre', '/assets/client-logos/hear-for-years.png', 'Awareness-led healthcare marketing for hearing tests, hearing aids, speech therapy, Meta Ads, and local enquiries.', 'The clinic had valuable services but needed stronger online visibility and a proper enquiry system. Many families delayed action because they were confused, worried, or unaware of early signs.', 'Create awareness, build trust, educate families, and generate quality enquiries for hearing aids, hearing tests, speech therapy, and consultations.', 'We created an awareness-to-enquiry funnel using educational posters, Meta Ads, social media management, and call/WhatsApp CTA content.', array['Lead Generation', 'Poster Creation', 'Meta Ads', 'Social Media Management']::text[], array['Instagram', 'Facebook', 'Meta Ads Manager', 'WhatsApp', 'Phone Calls']::text[], array['Built an awareness-to-enquiry funnel: create awareness, build trust, explain the solution, push to call or WhatsApp, and convert into consultation.', 'Targeted parents, children, adults, senior citizens, and nearby families who may need hearing or speech support.', 'Created content that encouraged early consultation for hearing difficulty, speech delay, unclear speech, and poor response to sound.', 'Focused ad campaigns on hearing aid, hearing test, speech therapy, and child speech delay enquiries.']::text[], array['Designed hearing aid awareness posters, speech delay creatives, hearing test promotions, senior citizen hearing care content, and CTA posters.', 'Managed Instagram and Facebook planning, captions, hashtags, stories, service posts, and page optimization.', 'Ran Meta Ads for local awareness, WhatsApp enquiries, parent-focused targeting, and hearing test campaigns.', 'Structured enquiry flow from ad or poster to call/WhatsApp, problem understanding, consultation booking, and service conversion.']::text[], 'A clearer healthcare digital presence with education-focused content and a local lead generation path for consultations.', '{"summary":"Local Reach: Focused, Awareness Content: Created, Consultation Funnel: Built"}'::jsonb, 'Healthcare Awareness Funnel', '', array[]::text[], 'Do not ignore hearing or speech problems. Early consultation can improve communication and confidence.', true) on conflict (slug) do update set client_name = excluded.client_name, industry = excluded.industry, logo_image_url = excluded.logo_image_url, short_description = excluded.short_description, problem = excluded.problem, goal = excluded.goal, solution = excluded.solution, services_provided = excluded.services_provided, platforms_used = excluded.platforms_used, strategy = excluded.strategy, execution = excluded.execution, results_summary = excluded.results_summary, metrics_json = excluded.metrics_json, cover_label = excluded.cover_label, testimonial = excluded.testimonial, published = excluded.published, updated_at = now();
insert into portfolio_cases (client_name, slug, industry, logo_image_url, short_description, problem, goal, solution, services_provided, platforms_used, strategy, execution, results_summary, metrics_json, cover_label, cover_image_url, gallery_images, testimonial, published) values ('Guna''s Craft', 'gunas-craft', 'Handmade Gifts / Paper Quilling Art / Corporate Gifting Brand', '/assets/client-logos/gunas-craft.jpg', 'Sales-focused storytelling for handmade gifts, paper quilling art, social impact, Meta Ads, and product enquiry generation.', 'The brand had beautiful handmade products but needed stronger digital visibility and a proper sales system. Customers needed to understand the effort, patience, creativity, and purpose behind every product.', 'Build emotional connection, improve premium product presentation, and generate enquiries for customized gifts, wall art, corporate gifting, and bulk orders.', 'We supported the brand with sales-focused marketing, Meta Ads, social media management, content creation, video shooting, video editing, and brand promotion.', array['Sales-Focused Marketing', 'Social Media Management', 'Content Creation', 'Video Shooting', 'Video Editing', 'Meta Ads']::text[], array['Instagram', 'Facebook', 'Meta Ads Manager', 'WhatsApp', 'DM Enquiries']::text[], array['Used an emotion-to-sales funnel: show handmade beauty, tell the story, build emotional value, create trust, generate enquiry, and convert into sales.', 'Positioned the products as meaningful handmade creations rather than normal gift items.', 'Built content around artisan effort, paper quilling detail, customized gifts, corporate gifting, wall art, and social impact.', 'Planned Meta Ads for product awareness, festival gifting, corporate gifting, DM enquiries, and retargeting.']::text[], array['Managed Instagram and Facebook content planning, reels, captions, hashtags, stories, product highlights, and enquiry CTAs.', 'Shot product close-ups, handmade process videos, wall art showcases, packaging shots, behind-the-scenes visuals, and lifestyle product content.', 'Edited product reveal reels, craft process edits, smooth transitions, emotional story videos, premium product edits, and ad creatives.', 'Created sales-focused campaigns for customized gifts, corporate gifts, bulk orders, festivals, weddings, and anniversaries.']::text[], 'A stronger emotional brand story and enquiry-focused sales funnel for handmade gifting and corporate order opportunities.', '{"summary":"Product Story: Stronger, Sales Enquiries: Focused, Brand Value: Elevated"}'::jsonb, 'Handmade Gift Sales Funnel', '', array[]::text[], 'Not just a gift. A handmade creation with patience, skill, and meaning.', true) on conflict (slug) do update set client_name = excluded.client_name, industry = excluded.industry, logo_image_url = excluded.logo_image_url, short_description = excluded.short_description, problem = excluded.problem, goal = excluded.goal, solution = excluded.solution, services_provided = excluded.services_provided, platforms_used = excluded.platforms_used, strategy = excluded.strategy, execution = excluded.execution, results_summary = excluded.results_summary, metrics_json = excluded.metrics_json, cover_label = excluded.cover_label, testimonial = excluded.testimonial, published = excluded.published, updated_at = now();
insert into portfolio_cases (client_name, slug, industry, logo_image_url, short_description, problem, goal, solution, services_provided, platforms_used, strategy, execution, results_summary, metrics_json, cover_label, cover_image_url, gallery_images, testimonial, published) values ('Taras Food Park', 'taras-food-park', 'Food Park / Multicuisine Restaurant Group / Cafe & Restaurant Brand', '/assets/client-logos/taras-food-park.jpg', 'A food destination marketing system for Yercaud tourists, families, food lovers, Meta Ads, reels, and footfall growth.', 'Taras Food Park had multiple restaurant brands and strong food offerings, but the digital presentation needed to be more structured, attractive, and clear for tourists and local customers.', 'Create awareness for all food options under one destination, improve visibility, promote location, and increase footfall, enquiries, and food orders.', 'We provided complete digital marketing support through social media management, Meta Ads, video shooting, video editing, content creation, branding content, and online promotion.', array['Social Media Management', 'Meta Ads', 'Video Shooting', 'Video Editing', 'Content Creation', 'Digital Marketing Support']::text[], array['Instagram', 'Facebook', 'Meta Ads Manager', 'Location-Based Promotion']::text[], array['Used a food destination funnel: show food variety, create craving, build trust, promote location, and increase footfall.', 'Positioned Taras Food Park as one place with multiple choices for family, friends, tourists, and local customers in Yercaud.', 'Created content around pure veg, cafe, Andhra food, grill, BBQ, shawarma, biryani, meals, fried rice, and multicuisine dining.', 'Planned location-based Meta Ads for tourists, families, food lovers, weekend visitors, and local audiences.']::text[], array['Managed Instagram and Facebook content planning, food reels, captions, hashtags, stories, menu highlights, offers, and festival posts.', 'Shot food close-ups, restaurant ambience, cafe visuals, grill and BBQ visuals, biryani and meals shots, family dining, service, location, and preparation videos.', 'Edited food reels with fast cuts, menu highlights, text overlays, trending audio, food color correction, offer announcements, and location CTA endings.', 'Built promotional content for each sub-brand including Water Front Multicuisine Restaurant, The Lake Cafe, Annalakshmi Pure Veg Restaurant, Andhra Spice, The Grill Box, and Rajavirunthu Grill Box.']::text[], 'A clearer digital identity for a multi-brand food park and a stronger content system to attract Yercaud tourists, families, and food lovers.', '{"summary":"Food Brands: Unified, Tourist Reach: Targeted, Footfall Funnel: Built"}'::jsonb, 'Food Park Footfall System', '', array[]::text[], 'One place. Multiple food choices. Perfect spot for family, friends, and tourists in Yercaud.', true) on conflict (slug) do update set client_name = excluded.client_name, industry = excluded.industry, logo_image_url = excluded.logo_image_url, short_description = excluded.short_description, problem = excluded.problem, goal = excluded.goal, solution = excluded.solution, services_provided = excluded.services_provided, platforms_used = excluded.platforms_used, strategy = excluded.strategy, execution = excluded.execution, results_summary = excluded.results_summary, metrics_json = excluded.metrics_json, cover_label = excluded.cover_label, testimonial = excluded.testimonial, published = excluded.published, updated_at = now();
insert into portfolio_cases (client_name, slug, industry, logo_image_url, short_description, problem, goal, solution, services_provided, platforms_used, strategy, execution, results_summary, metrics_json, cover_label, cover_image_url, gallery_images, testimonial, published) values ('SHEVAROYS', 'shevaroys', 'Hotel Management College / Hospitality Education Institution', '/assets/client-logos/shevaroys.png', 'An admission enquiry funnel for a hospitality education brand using Meta Ads, WhatsApp marketing, shooting, editing, and social media.', 'SHEVAROYS had strong education value and hospitality training, but needed a powerful digital presence to reach students and parents who require trust before choosing a course.', 'Increase admission enquiries, improve visibility, build trust among parents and students, and generate quality leads for hotel management courses.', 'We delivered end-to-end digital marketing with social media, Meta Ads, WhatsApp marketing, shooting, editing, and lead generation campaigns.', array['End-to-End Digital Marketing', 'Video Shooting', 'Video Editing', 'Meta Ads Campaigns', 'Lead Generation', 'WhatsApp Marketing', 'Social Media Management']::text[], array['Instagram', 'Facebook', 'Meta Ads Manager', 'WhatsApp', 'Admission Counselling']::text[], array['Built an admission funnel: ad or reel, WhatsApp click, course enquiry, counselling, and admission follow-up.', 'Created content to answer parent and student doubts about course value, job opportunities, safety, placement support, credibility, fees, hostel facilities, and future scope.', 'Targeted students after 10th and 12th, diploma seekers, parents, and students looking for job-oriented hospitality courses.', 'Used WhatsApp as the main conversion channel for course details, brochure sharing, reminders, and follow-up.']::text[], array['Planned admission campaigns, content calendars, creative direction, lead generation strategy, and WhatsApp enquiry flow.', 'Shot campus videos, practical training sessions, cooking and food production classes, student activities, classroom learning, faculty interaction, ambience, and admission promos.', 'Edited reels, admission videos, course highlights, student life content, text overlay hooks, CTA endings, and WhatsApp callouts.', 'Managed Instagram and Facebook posts, captions, hashtags, admission-focused creatives, career awareness content, event posts, and enquiry CTAs.']::text[], 'A professional education marketing system that improved admission communication and moved interested students into WhatsApp counselling.', '{"summary":"Admission Funnel: Built, Parent Trust: Supported, Student Leads: Focused"}'::jsonb, 'Hospitality Admission Funnel', '', array[]::text[], 'A clear digital path from course awareness to WhatsApp enquiry and admission counselling.', true) on conflict (slug) do update set client_name = excluded.client_name, industry = excluded.industry, logo_image_url = excluded.logo_image_url, short_description = excluded.short_description, problem = excluded.problem, goal = excluded.goal, solution = excluded.solution, services_provided = excluded.services_provided, platforms_used = excluded.platforms_used, strategy = excluded.strategy, execution = excluded.execution, results_summary = excluded.results_summary, metrics_json = excluded.metrics_json, cover_label = excluded.cover_label, testimonial = excluded.testimonial, published = excluded.published, updated_at = now();

insert into services (title, slug, short_description, pain_point, detailed_description, deliverables, icon, image_url, active, display_order) values ('Meta Ads & Lead Generation', 'meta-ads-lead-generation', 'Targeted Meta campaigns built for quality enquiries, calls, and follow-up ready leads.', 'Random boosting spends money without building a predictable lead pipeline.', 'We plan audience segments, offers, creatives, landing flows, and lead tracking so every campaign has a conversion path.', array['Campaign strategy', 'Audience setup', 'Ad creatives', 'Lead forms or landing pages', 'Weekly optimization']::text[], 'Megaphone', '', true, 1) on conflict (slug) do update set title = excluded.title, short_description = excluded.short_description, pain_point = excluded.pain_point, detailed_description = excluded.detailed_description, deliverables = excluded.deliverables, icon = excluded.icon, image_url = excluded.image_url, active = excluded.active, display_order = excluded.display_order;
insert into services (title, slug, short_description, pain_point, detailed_description, deliverables, icon, image_url, active, display_order) values ('Google Ads', 'google-ads', 'Search campaigns that reach buyers when they are already looking for your service.', 'High-intent searches are expensive when keywords, match types, and tracking are loose.', 'We structure search campaigns around service intent, call actions, enquiry forms, and measurable conversions.', array['Keyword planning', 'Search campaign setup', 'Conversion tracking', 'Ad copy testing', 'Performance reporting']::text[], 'Search', '', true, 2) on conflict (slug) do update set title = excluded.title, short_description = excluded.short_description, pain_point = excluded.pain_point, detailed_description = excluded.detailed_description, deliverables = excluded.deliverables, icon = excluded.icon, image_url = excluded.image_url, active = excluded.active, display_order = excluded.display_order;
insert into services (title, slug, short_description, pain_point, detailed_description, deliverables, icon, image_url, active, display_order) values ('Website Development', 'website-development', 'Modern, mobile-first, SEO-ready websites that make your business easier to trust and contact.', 'A weak website turns paid traffic into missed trust, missed enquiries, and missed sales.', 'We build premium pages, conversion sections, contact paths, and technical foundations ready for SEO and ads.', array['Responsive website', 'Landing pages', 'SEO structure', 'Contact integrations', 'Speed-focused build']::text[], 'MonitorSmartphone', '', true, 3) on conflict (slug) do update set title = excluded.title, short_description = excluded.short_description, pain_point = excluded.pain_point, detailed_description = excluded.detailed_description, deliverables = excluded.deliverables, icon = excluded.icon, image_url = excluded.image_url, active = excluded.active, display_order = excluded.display_order;
insert into services (title, slug, short_description, pain_point, detailed_description, deliverables, icon, image_url, active, display_order) values ('Business Automation', 'business-automation', 'Follow-up systems for enquiries, lead tracking, WhatsApp flows, CRM, and daily workflows.', 'Leads go cold when follow-up is slow, scattered, or dependent on memory.', 'We connect enquiry sources with simple automation so your team can respond faster and track every opportunity.', array['Lead routing', 'WhatsApp follow-ups', 'CRM setup', 'Workflow automation', 'Status tracking']::text[], 'Workflow', '', true, 4) on conflict (slug) do update set title = excluded.title, short_description = excluded.short_description, pain_point = excluded.pain_point, detailed_description = excluded.detailed_description, deliverables = excluded.deliverables, icon = excluded.icon, image_url = excluded.image_url, active = excluded.active, display_order = excluded.display_order;
insert into services (title, slug, short_description, pain_point, detailed_description, deliverables, icon, image_url, active, display_order) values ('Video Shooting & Editing', 'video-shooting-editing', 'Brand videos, reels, ad videos, and promotional content shaped for attention and trust.', 'Businesses often have good offers but weak visuals that fail to stop the scroll.', 'We plan concepts, shoot brand-focused footage, edit for platform behavior, and prepare creative variations.', array['Shoot planning', 'Reels', 'Ad videos', 'Promotional edits', 'Format exports']::text[], 'Video', '', true, 5) on conflict (slug) do update set title = excluded.title, short_description = excluded.short_description, pain_point = excluded.pain_point, detailed_description = excluded.detailed_description, deliverables = excluded.deliverables, icon = excluded.icon, image_url = excluded.image_url, active = excluded.active, display_order = excluded.display_order;
insert into services (title, slug, short_description, pain_point, detailed_description, deliverables, icon, image_url, active, display_order) values ('Creative Design', 'creative-design', 'Posters, ad creatives, social media designs, banners, brand kits, and campaign visuals.', 'Inconsistent design makes even strong businesses feel unprepared online.', 'We create polished design systems and campaign assets that make your brand look clear, premium, and consistent.', array['Poster design', 'Ad creatives', 'Social media templates', 'Banners', 'Brand kit support']::text[], 'Palette', '', true, 6) on conflict (slug) do update set title = excluded.title, short_description = excluded.short_description, pain_point = excluded.pain_point, detailed_description = excluded.detailed_description, deliverables = excluded.deliverables, icon = excluded.icon, image_url = excluded.image_url, active = excluded.active, display_order = excluded.display_order;
insert into services (title, slug, short_description, pain_point, detailed_description, deliverables, icon, image_url, active, display_order) values ('SEO', 'seo', 'Website and content optimization for better organic visibility and long-term presence.', 'Paid ads work faster, but businesses lose long-term discovery when SEO is ignored.', 'We improve page structure, content relevance, search visibility, and local discovery signals.', array['Keyword mapping', 'On-page SEO', 'Content planning', 'Technical fixes', 'Local visibility support']::text[], 'LineChart', '', true, 7) on conflict (slug) do update set title = excluded.title, short_description = excluded.short_description, pain_point = excluded.pain_point, detailed_description = excluded.detailed_description, deliverables = excluded.deliverables, icon = excluded.icon, image_url = excluded.image_url, active = excluded.active, display_order = excluded.display_order;
insert into services (title, slug, short_description, pain_point, detailed_description, deliverables, icon, image_url, active, display_order) values ('Social Media Management', 'social-media-management', 'Content planning and publishing systems that keep your brand visible, useful, and consistent.', 'Posting without a content plan creates noise but not audience trust.', 'We shape monthly content themes, creatives, captions, reels, and platform-ready posting calendars.', array['Monthly planner', 'Caption strategy', 'Creative direction', 'Content calendar', 'Performance review']::text[], 'Share2', '', true, 8) on conflict (slug) do update set title = excluded.title, short_description = excluded.short_description, pain_point = excluded.pain_point, detailed_description = excluded.detailed_description, deliverables = excluded.deliverables, icon = excluded.icon, image_url = excluded.image_url, active = excluded.active, display_order = excluded.display_order;
insert into services (title, slug, short_description, pain_point, detailed_description, deliverables, icon, image_url, active, display_order) values ('Sales Funnel & Follow-Up System', 'sales-funnel-follow-up', 'Landing pages, WhatsApp flows, and communication systems that convert leads into customers.', 'Leads do not become revenue unless the journey after the enquiry is clear.', 'We map the path from ad click to enquiry to follow-up so sales conversations happen with better timing and context.', array['Landing page flow', 'Lead magnets', 'WhatsApp scripts', 'Follow-up sequences', 'Sales message support']::text[], 'Route', '', true, 9) on conflict (slug) do update set title = excluded.title, short_description = excluded.short_description, pain_point = excluded.pain_point, detailed_description = excluded.detailed_description, deliverables = excluded.deliverables, icon = excluded.icon, image_url = excluded.image_url, active = excluded.active, display_order = excluded.display_order;

insert into team_members (name, role, bio, image_url, skills, instagram_url, linkedin_url, display_order, active) values ('Prasanth M', 'Founder, Zigo Digital', 'Prasanth M is the Founder of Zigo Digital, leading the agency with practical digital marketing experience across performance marketing, lead generation, content planning, website strategy, automation, and client communication. He founded Zigo Digital to help businesses build clear digital growth systems that attract the right audience, generate quality enquiries, and convert attention into sales.', '/assets/founder-prasanth.png', array['Performance Marketing', 'Lead Generation', 'Digital Strategy', 'Content Planning', 'Website Strategy', 'Business Automation', 'Client Communication', 'Sales Funnel Planning']::text[], '', '', 1, true);
insert into team_members (name, role, bio, image_url, skills, instagram_url, linkedin_url, display_order, active) values ('Surya M', 'Co Founder & CEO, Zigo Digital', 'Surya is the CEO, Project Manager, and Graphic Designer at Zigo Digital, leading creative direction, client coordination, and project execution. With a strong eye for design and branding, he manages end-to-end digital projects, ensuring every design, campaign, and creative output matches the client''s business goals. His role combines leadership, strategy, and creativity to deliver high-quality digital solutions for brands.', 'https://res.cloudinary.com/domt6qtye/image/upload/v1781249303/WhatsApp_Image_2026-06-12_at_12.56.36_PM_ra1rqj.jpg', array['Team Handling', 'Project Management', 'Client Coordination', 'Graphic Designing', 'Branding', 'Creative Direction', 'Social Media Design', 'Content Planning', 'Problem Solving']::text[], '', '', 2, true);

insert into blog_posts (title, slug, excerpt, content, category, tags, cover_image_url, author, published, featured, published_at, updated_at, seo_title, seo_description, canonical_url) values ('What I Am Learning About Digital Growth Systems', 'digital-growth-systems', 'A practical note from Prasanth M on connecting content, ads, websites, automation, and follow-up into one clear growth path.', '## Quick answer
Digital marketing works better when every channel has a clear job. Content builds trust, ads create demand, websites explain the offer, and follow-up converts enquiries into sales.

## What I am learning
Many businesses do not need only posting or only ads. They need a complete digital growth system where every click has a next step.

- Content should answer doubts before the customer asks.
- Ads should bring the right enquiry, not just more views.
- Websites should make the offer clear and easy to trust.
- WhatsApp, calls, and automation should help the team follow up faster.
- SEO and answer-focused content should make the brand discoverable for long-term searches.

## How this applies at Zigo Digital
At Zigo Digital, I am learning to connect strategy, creative, performance marketing, AI tools, and local business understanding into one practical system.

See our [services](/services), explore client [portfolio case studies](/portfolio), or contact us for a [free consultation](/contact).

For search basics, I also follow official resources like [Google Search Central](https://developers.google.com/search).', 'Marketing Learning', array['Digital Marketing', 'Lead Generation', 'AI Tools', 'SEO']::text[], '/assets/digital-marketing-hero.png', 'Prasanth M', true, true, '2026-06-12T00:00:00.000Z', '2026-06-12T00:00:00.000Z', 'What I Am Learning About Digital Growth Systems', 'Prasanth M shares practical learning about content, ads, websites, automation, AI tools, SEO, and lead generation for business growth.', '') on conflict (slug) do update set title = excluded.title, excerpt = excluded.excerpt, content = excluded.content, category = excluded.category, tags = excluded.tags, cover_image_url = excluded.cover_image_url, author = excluded.author, published = excluded.published, featured = excluded.featured, published_at = excluded.published_at, updated_at = excluded.updated_at, seo_title = excluded.seo_title, seo_description = excluded.seo_description, canonical_url = excluded.canonical_url;
